<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Personal Expense Tracker</title>
<style>
  * { box-sizing: border-box; }
  body {
    margin: 0;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    background: #f3f4f6;
    color: #1f2937;
  }
  main { max-width: 720px; margin: 0 auto; padding: 24px 16px 48px; }
  h1 { font-size: 1.5rem; margin: 0 0 16px; }
  h2 { font-size: 1.05rem; margin: 0 0 12px; }
  form, section {
    background: #ffffff;
    border: 1px solid #e5e7eb;
    border-radius: 8px;
    padding: 16px;
    margin-bottom: 16px;
  }
  .fields {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(150px, 1fr));
    gap: 12px;
  }
  .field label {
    display: block;
    font-size: 0.8rem;
    font-weight: 600;
    color: #4b5563;
    margin-bottom: 4px;
  }
  .muted { font-weight: 400; color: #9ca3af; }
  input, select {
    width: 100%;
    padding: 8px 10px;
    border: 1px solid #cbd5e1;
    border-radius: 6px;
    font-size: 0.9rem;
    background: #fff;
  }
  input:focus, select:focus {
    outline: 2px solid #93c5fd;
    border-color: #2563eb;
  }
  button { cursor: pointer; font: inherit; }
  #add-expense {
    margin-top: 12px;
    padding: 9px 18px;
    background: #2563eb;
    color: #fff;
    border: none;
    border-radius: 6px;
    font-size: 0.95rem;
  }
  #add-expense:hover { background: #1d4ed8; }
  #form-error {
    color: #b91c1c;
    font-size: 0.85rem;
    min-height: 1.2em;
    margin: 8px 0 0;
  }
  .total-line { font-size: 1.05rem; margin: 0 0 10px; }
  #total { font-weight: 700; }
  .cat-totals { display: flex; flex-wrap: wrap; gap: 6px; }
  .cat-total {
    display: inline-block;
    padding: 4px 12px;
    background: #eef2ff;
    border: 1px solid #e0e7ff;
    border-radius: 999px;
    font-size: 0.85rem;
  }
  .expense {
    display: flex;
    justify-content: space-between;
    align-items: center;
    gap: 12px;
    padding: 9px 6px;
    border-bottom: 1px solid #eee;
  }
  .expense:last-child { border-bottom: none; }
  .exp-text { font-size: 0.95rem; word-break: break-word; }
  .exp-del {
    flex-shrink: 0;
    background: #fef2f2;
    color: #b91c1c;
    border: 1px solid #fecaca;
    border-radius: 6px;
    padding: 4px 12px;
    font-size: 0.8rem;
  }
  .exp-del:hover { background: #fee2e2; }
  .empty { color: #6b7280; font-size: 0.9rem; margin: 4px 0; }
</style>
</head>
<body>
<main>
  <h1>Personal Expense Tracker</h1>

  <form id="expense-form" novalidate autocomplete="off">
    <h2>Add an expense</h2>
    <div class="fields">
      <div class="field">
        <label for="amount">Amount</label>
        <input id="amount" type="number" step="0.01" placeholder="e.g. 12.50">
      </div>
      <div class="field">
        <label for="category">Category</label>
        <select id="category">
          <option value="groceries">groceries</option>
          <option value="transport">transport</option>
          <option value="bills">bills</option>
          <option value="fun">fun</option>
        </select>
      </div>
      <div class="field">
        <label for="date">Date</label>
        <input id="date" type="date">
      </div>
      <div class="field">
        <label for="note">Note <span class="muted">(optional)</span></label>
        <input id="note" type="text" placeholder="e.g. weekly shop">
      </div>
    </div>
    <button id="add-expense" type="submit">Add expense</button>
    <p id="form-error" role="alert"></p>
  </form>

  <section aria-labelledby="filters-h">
    <h2 id="filters-h">Filters</h2>
    <div class="fields">
      <div class="field">
        <label for="filter-category">Category</label>
        <select id="filter-category">
          <option value="all">all</option>
          <option value="groceries">groceries</option>
          <option value="transport">transport</option>
          <option value="bills">bills</option>
          <option value="fun">fun</option>
        </select>
      </div>
      <div class="field">
        <label for="filter-from">From date</label>
        <input id="filter-from" type="date">
      </div>
      <div class="field">
        <label for="filter-to">To date</label>
        <input id="filter-to" type="date">
      </div>
    </div>
  </section>

  <section aria-labelledby="summary-h">
    <h2 id="summary-h">Summary (visible expenses)</h2>
    <p class="total-line">Total: <span id="total">0.00</span></p>
    <div class="cat-totals">
      <span class="cat-total" data-cat="groceries">groceries: 0.00</span>
      <span class="cat-total" data-cat="transport">transport: 0.00</span>
      <span class="cat-total" data-cat="bills">bills: 0.00</span>
      <span class="cat-total" data-cat="fun">fun: 0.00</span>
    </div>
  </section>

  <section aria-labelledby="list-h">
    <h2 id="list-h">Expenses</h2>
    <div id="expense-list"></div>
  </section>
</main>

<script>
(function () {
  "use strict";

  var STORAGE_KEY = "expenses";
  var CATEGORIES = ["groceries", "transport", "bills", "fun"];

  var formEl = document.getElementById("expense-form");
  var amountEl = document.getElementById("amount");
  var categoryEl = document.getElementById("category");
  var dateEl = document.getElementById("date");
  var noteEl = document.getElementById("note");
  var errorEl = document.getElementById("form-error");
  var listEl = document.getElementById("expense-list");
  var totalEl = document.getElementById("total");
  var filterCatEl = document.getElementById("filter-category");
  var filterFromEl = document.getElementById("filter-from");
  var filterToEl = document.getElementById("filter-to");

  function load() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (!raw) return [];
      var data = JSON.parse(raw);
      if (!Array.isArray(data)) return [];
      return data.filter(function (e) {
        return e &&
               typeof e.amount === "number" && isFinite(e.amount) &&
               typeof e.category === "string" &&
               typeof e.date === "string" && e.date.length > 0;
      });
    } catch (err) {
      return [];
    }
  }

  function save() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
    } catch (err) {
      /* storage unavailable; app still works for this session */
    }
  }

  var expenses = load();
  var nextId = 1;
  expenses.forEach(function (e) {
    if (typeof e.id === "number" && e.id >= nextId) nextId = e.id + 1;
  });

  function fmt(n) {
    return n.toFixed(2);
  }

  function visibleExpenses() {
    var cat = filterCatEl.value;
    var from = filterFromEl.value;
    var to = filterToEl.value;
    return expenses
      .filter(function (e) {
        if (cat !== "all" && e.category !== cat) return false;
        if (from && e.date < from) return false;
        if (to && e.date > to) return false;
        return true;
      })
      .sort(function (a, b) {
        if (a.date < b.date) return 1;
        if (a.date > b.date) return -1;
        return (b.id || 0) - (a.id || 0);
      });
  }

  function render() {
    var visible = visibleExpenses();

    listEl.innerHTML = "";
    if (visible.length === 0) {
      var empty = document.createElement("p");
      empty.className = "empty";
      empty.textContent = "No expenses to show.";
      listEl.appendChild(empty);
    } else {
      visible.forEach(function (e) {
        var row = document.createElement("div");
        row.className = "expense";
        row.setAttribute("data-id", String(e.id));

        var text = document.createElement("span");
        text.className = "exp-text";
        var line = fmt(e.amount) + " \u00B7 " + e.category + " \u00B7 " + e.date;
        if (e.note) line += " \u2014 " + e.note;
        text.textContent = line;

        var del = document.createElement("button");
        del.type = "button";
        del.className = "exp-del";
        del.setAttribute("data-id", String(e.id));
        del.textContent = "Delete";

        row.appendChild(text);
        row.appendChild(del);
        listEl.appendChild(row);
      });
    }

    var total = 0;
    visible.forEach(function (e) { total += e.amount; });
    totalEl.textContent = fmt(total);

    CATEGORIES.forEach(function (c) {
      var sum = 0;
      visible.forEach(function (e) {
        if (e.category === c) sum += e.amount;
      });
      var el = document.querySelector('.cat-total[data-cat="' + c + '"]');
      if (el) el.textContent = c + ": " + fmt(sum);
    });
  }

  formEl.addEventListener("submit", function (ev) {
    ev.preventDefault();

    var raw = amountEl.value.trim();
    var amount = amountEl.valueAsNumber;

    if (raw === "" || typeof amount !== "number" || isNaN(amount) || !isFinite(amount)) {
      errorEl.textContent = "Please enter a valid amount.";
      return;
    }
    if (amount <= 0) {
      errorEl.textContent = "Amount must be greater than zero.";
      return;
    }
    if (!dateEl.value) {
      errorEl.textContent = "Please choose a date.";
      return;
    }

    expenses.push({
      id: nextId++,
      amount: Math.round(amount * 100) / 100,
      category: categoryEl.value,
      date: dateEl.value,
      note: noteEl.value.trim()
    });
    save();

    errorEl.textContent = "";
    amountEl.value = "";
    noteEl.value = "";
    render();
  });

  listEl.addEventListener("click", function (ev) {
    var t = ev.target;
    while (t && t !== listEl && !(t.classList && t.classList.contains("exp-del"))) {
      t = t.parentNode;
    }
    if (!t || t === listEl) return;
    var id = Number(t.getAttribute("data-id"));
    expenses = expenses.filter(function (e) { return e.id !== id; });
    save();
    render();
  });

  [filterCatEl, filterFromEl, filterToEl].forEach(function (el) {
    el.addEventListener("change", render);
    el.addEventListener("input", render);
  });

  render();
})();
</script>
</body>
</html>
